 1	import { useMemo } from 'react';
 2	
 3	import { InfrastructureModel, modelToGroupVersionKind } from '@kubevirt-ui/kubevirt-api/console';
 4	import {
 5	  K8sResourceCommon,
 6	  K8sVerb,
 7	  useAccessReview,
 8	  useK8sWatchResource,
 9	} from '@openshift-console/dynamic-plugin-sdk';
10	
11	type UseSingleNodeCluster = () => [isSingleNodeCluster: boolean, loaded: boolean];
12	const useSingleNodeCluster: UseSingleNodeCluster = () => {
13	  const [canAccessInfra] = useAccessReview({
14	    group: InfrastructureModel.apiGroup,
15	    resource: InfrastructureModel.plural,
16	    verb: 'list' as K8sVerb,
17	  });
18	
19	  const [infrastructure, loaded] = useK8sWatchResource<
20	    K8sResourceCommon & {
21	      status: { infrastructureTopology: string };
22	    }
23	  >({
24	    groupVersionKind: modelToGroupVersionKind(InfrastructureModel),
25	    namespaced: false,
26	  });
27	
28	  const isSingleNodeCluster = useMemo(
29	    () => infrastructure?.status?.infrastructureTopology === 'SingleReplica',
30	    [infrastructure],
31	  );
32	
33	  return canAccessInfra ? [isSingleNodeCluster, loaded] : [undefined, true];
34	};
35	
36	export default useSingleNodeCluster;

